SELECT DISTINCT ?winner ?winnerLabel WHERE {
  ?winner wdt:P166 ?award.
  ?award rdfs:label ?awardLabel.
  FILTER(CONTAINS(LCASE(?awardLabel), "best boy band") && CONTAINS(LCASE(?awardLabel), "iheartradio"))
  FILTER(LANG(?awardLabel) = "en")
  OPTIONAL { ?winner rdfs:label ?winnerLabel FILTER(LANG(?winnerLabel) = "en") }
}
LIMIT 10

